import java.io.*;

public class InsecureDeserializationExample {

    public static void main(String[] args) {
        try {
            // Simulate user input by reading a serialized object from a file
            ObjectInputStream ois = new ObjectInputStream(new FileInputStream("user_input.ser"));
            Object obj = ois.readObject();

            // Perform some operation on the deserialized object
            if (obj instanceof String) {
                System.out.println("Deserialized value: " + obj);
            } else {
                System.out.println("Invalid input type");
            }

        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
        }
    }
}

